solutions.javascript:
// Solution
function aggregationPipeline(interactions) {
    let pipeline = [
        {
            $match: {
                interactionType: { $in: ['click', 'view'] }
            }
        },
        {
            $project: {
                timestamp: 1,
                name: {
                    $cond: [
                        {
                            $and: [
                                { $eq: ['interactionType', 'click'] },
                                { $eq: ['age', { $gte: '$$age' }] } // FIXED: use variable age
                            ]
                        },
                        { $concat: ['$name', ''] },
                        null
                    ]
                }
            }
        }
    ];
    pipeline.push({ $project: { age: 0 } });
    return pipeline;
}
